import type { SSHService } from '../../SSHService';
import type {
  MigrationProvider,
  ProviderDetectionResult,
  DiscoveredItem,
  ScanProgress,
  DecommissionPlan,
  DecommissionStep,
} from '../types';

export interface ProviderScanContext {
  migrationId: string;
  serverId: string;
  sshService: SSHService;
  emitProgress: (progress: ScanProgress) => void;
}

export abstract class BaseProvider {
  abstract readonly providerId: MigrationProvider;
  abstract readonly displayName: string;
  abstract readonly description: string;

  /** Detect if this provider manages the target server. Returns confidence 0-1. */
  abstract detect(serverId: string, sshService: SSHService): Promise<ProviderDetectionResult>;

  /** Scan the server for all discoverable items managed by this provider. */
  abstract scan(ctx: ProviderScanContext): Promise<DiscoveredItem[]>;

  /** Generate a decommission plan. Returns null if no agent to remove (e.g., raw_vps). */
  abstract getDecommissionPlan(serverId: string, sshService: SSHService): Promise<DecommissionPlan | null>;

  /** Execute a single decommission step. */
  async executeDecommissionStep(
    serverId: string,
    sshService: SSHService,
    step: DecommissionStep
  ): Promise<{ success: boolean; output: string }> {
    try {
      const result = await sshService.executeCommand(serverId, step.command);
      return { success: result.exitCode === 0, output: result.stdout || result.stderr };
    } catch (err) {
      return { success: false, output: err instanceof Error ? err.message : String(err) };
    }
  }

  /** Helper: check if a systemctl service is active using exact match (not .includes). */
  protected async isServiceActive(serverId: string, sshService: SSHService, serviceName: string): Promise<boolean> {
    try {
      const result = await sshService.executeCommand(serverId, `systemctl is-active ${serviceName} 2>/dev/null`);
      return result.stdout.trim().split('\n').some(line => line.trim() === 'active');
    } catch {
      return false;
    }
  }

  /** Helper: check if a Docker container exists by name filter. */
  protected async dockerContainerExists(serverId: string, sshService: SSHService, nameFilter: string): Promise<boolean> {
    try {
      const result = await sshService.executeCommand(
        serverId,
        `docker ps --filter "name=${nameFilter}" --format "{{.Names}}" 2>/dev/null`
      );
      return result.exitCode === 0 && result.stdout.trim().length > 0;
    } catch {
      return false;
    }
  }

  /** Helper: check if a path exists on the remote server. */
  protected async pathExists(serverId: string, sshService: SSHService, remotePath: string): Promise<boolean> {
    try {
      const result = await sshService.executeCommand(serverId, `test -e ${remotePath} && echo "exists"`);
      return result.stdout.trim() === 'exists';
    } catch {
      return false;
    }
  }

  /** Helper: safely execute a command, returning empty string on failure. */
  protected async safeExec(serverId: string, sshService: SSHService, command: string): Promise<string> {
    try {
      const result = await sshService.executeCommand(serverId, command);
      return result.exitCode === 0 ? result.stdout.trim() : '';
    } catch {
      return '';
    }
  }
}
